     1→import { useState, useEffect, useCallback } from 'react';
     2→import {
     3→  Modal,
     4→  ModalBody,
     5→  ModalHeader,
     6→  ModalVariant,
     7→  Button,
     8→  Card,
     9→  CardBody,
    10→  Content,
    11→  EmptyState,
    12→  EmptyStateBody,
    13→  EmptyStateFooter,
    14→  EmptyStateActions,
    15→  Split,
    16→  SplitItem,
    17→  Stack,
    18→  StackItem,
    19→  Label,
    20→  Alert,
    21→  AlertActionCloseButton,
    22→  Spinner,
    23→  Icon,
    24→} from '@patternfly/react-core';
    25→import {
    26→  FolderIcon,
    27→  FolderOpenIcon,
    28→  TimesIcon,
    29→  PlusCircleIcon,
    30→} from '@patternfly/react-icons';
    31→import { open } from '@tauri-apps/plugin-dialog';
    32→import { invoke } from '@tauri-apps/api/core';
    33→import { motion, AnimatePresence } from 'motion/react';
    34→
    35→// Local storage key for recent projects
    36→const RECENT_PROJECTS_KEY = 'hq_recent_projects';
    37→const MAX_RECENT_PROJECTS = 10;
    38→
    39→export interface RecentProject {
    40→  path: string;
    41→  name: string;
    42→  lastOpened: number;
    43→  isValid?: boolean;
    44→}
    45→
    46→interface ProjectSelectorProps {
    47→  isOpen: boolean;
    48→  onClose: () => void;
    49→  onSelectProject: (path: string, name: string) => void;
    50→}
    51→
    52→// Validate if a folder is a valid harness project (has .harness folder)
    53→async function validateHarnessProject(path: string): Promise<boolean> {
    54→  try {
    55→    // Use Tauri invoke to check if .harness directory exists
    56→    const exists = await invoke<boolean>('check_harness_exists', { path });
    57→    return exists;
    58→  } catch {
    59→    // Fallback: assume valid if we can't check
    60→    return true;
    61→  }
    62→}
    63→
    64→// Get project name from path
    65→function getProjectName(path: string): string {
    66→  const parts = path.split(/[/\\]/);
    67→  return parts[parts.length - 1] || 'Unknown Project';
    68→}
    69→
    70→// Load recent projects from localStorage
    71→function loadRecentProjects(): RecentProject[] {
    72→  try {
    73→    const stored = localStorage.getItem(RECENT_PROJECTS_KEY);
    74→    if (stored) {
    75→      return JSON.parse(stored);
    76→    }
    77→  } catch (e) {
    78→    console.error('Failed to load recent projects:', e);
    79→  }
    80→  return [];
    81→}
    82→
    83→// Save recent projects to localStorage
    84→function saveRecentProjects(projects: RecentProject[]): void {
    85→  try {
    86→    localStorage.setItem(RECENT_PROJECTS_KEY, JSON.stringify(projects));
    87→  } catch (e) {
    88→    console.error('Failed to save recent projects:', e);
    89→  }
    90→}
    91→
    92→// Add a project to recent projects
    93→function addToRecentProjects(path: string, name: string): void {
    94→  const projects = loadRecentProjects();
    95→
    96→  // Remove if already exists
    97→  const filtered = projects.filter((p) => p.path !== path);
    98→
    99→  // Add to front
   100→  filtered.unshift({
   101→    path,
   102→    name,
   103→    lastOpened: Date.now(),
   104→    isValid: true,
   105→  });
   106→
   107→  // Keep only MAX_RECENT_PROJECTS
   108→  const trimmed = filtered.slice(0, MAX_RECENT_PROJECTS);
   109→
   110→  saveRecentProjects(trimmed);
   111→}
   112→
   113→// Remove a project from recent projects
   114→function removeFromRecentProjects(path: string): RecentProject[] {
   115→  const projects = loadRecentProjects();
   116→  const filtered = projects.filter((p) => p.path !== path);
   117→  saveRecentProjects(filtered);
   118→  return filtered;
   119→}
   120→
   121→export function ProjectSelector({
   122→  isOpen,
   123→  onClose,
   124→  onSelectProject,
   125→}: ProjectSelectorProps): React.JSX.Element {
   126→  const [recentProjects, setRecentProjects] = useState<RecentProject[]>([]);
   127→  const [isLoading, setIsLoading] = useState(false);
   128→  const [error, setError] = useState<string | null>(null);
   129→  const [validatingProjects, setValidatingProjects] = useState(false);
   130→
   131→  // State for "init harness" confirmation
   132→  const [pendingInitPath, setPendingInitPath] = useState<string | null>(null);
   133→  const [isInitializing, setIsInitializing] = useState(false);
   134→
   135→  // Load recent projects on mount
   136→  useEffect(() => {
   137→    if (isOpen) {
   138→      const projects = loadRecentProjects();
   139→      setRecentProjects(projects);
   140→      setError(null);
   141→
   142→      // Validate projects in background
   143→      validateRecentProjects(projects);
   144→    }
   145→  }, [isOpen]);
   146→
   147→  // Validate recent projects in background
   148→  const validateRecentProjects = useCallback(async (projects: RecentProject[]) => {
   149→    if (projects.length === 0) return;
   150→
   151→    setValidatingProjects(true);
   152→
   153→    const validated = await Promise.all(
   154→      projects.map(async (project) => ({
   155→        ...project,
   156→        isValid: await validateHarnessProject(project.path),
   157→      }))
   158→    );
   159→
   160→    setRecentProjects(validated);
   161→    setValidatingProjects(false);
   162→  }, []);
   163→
   164→  // Handle browse folder
   165→  const handleBrowse = useCallback(async () => {
   166→    setIsLoading(true);
   167→    setError(null);
   168→    setPendingInitPath(null);
   169→
   170→    try {
   171→      const selected = await open({
   172→        directory: true,
   173→        multiple: false,
   174→        title: 'Select Project Folder',
   175→      });
   176→
   177→      if (selected && typeof selected === 'string') {
   178→        // Validate it's a harness project
   179→        const isValid = await validateHarnessProject(selected);
   180→
   181→        if (!isValid) {
   182→          // Ask if user wants to initialize harness
   183→          setPendingInitPath(selected);
   184→          setIsLoading(false);
   185→          return;
   186→        }
   187→
   188→        const name = getProjectName(selected);
   189→        addToRecentProjects(selected, name);
   190→        onSelectProject(selected, name);
   191→        onClose();
   192→      }
   193→    } catch (e) {
   194→      console.error('Failed to open directory:', e);
   195→      setError('Failed to open folder picker. Please try again.');
   196→    } finally {
   197→      setIsLoading(false);
   198→    }
   199→  }, [onSelectProject, onClose]);
   200→
   201→  // Handle initializing harness in a folder
   202→  const handleInitHarness = useCallback(async () => {
   203→    if (!pendingInitPath) return;
   204→
   205→    setIsInitializing(true);
   206→    setError(null);
   207→
   208→    try {
   209→      // Run harness init command
   210→      await invoke('run_harness_command', {
   211→        projectPath: pendingInitPath,
   212→        args: ['init'],
   213→      });
   214→
   215→      // Verify it worked
   216→      const isValid = await validateHarnessProject(pendingInitPath);
   217→      if (!isValid) {
   218→        setError('Failed to initialize harness. Please try again.');
   219→        setIsInitializing(false);
   220→        return;
   221→      }
   222→
   223→      const name = getProjectName(pendingInitPath);
   224→      addToRecentProjects(pendingInitPath, name);
   225→      onSelectProject(pendingInitPath, name);
   226→      setPendingInitPath(null);
   227→      onClose();
   228→    } catch (e) {
   229→      console.error('Failed to initialize harness:', e);
   230→      setError(`Failed to initialize harness: ${e}`);
   231→    } finally {
   232→      setIsInitializing(false);
   233→    }
   234→  }, [pendingInitPath, onSelectProject, onClose]);
   235→
   236→  // Cancel pending init
   237→  const handleCancelInit = useCallback(() => {
   238→    setPendingInitPath(null);
   239→  }, []);
   240→
   241→  // Handle select recent project
   242→  const handleSelectRecent = useCallback(async (project: RecentProject) => {
   243→    setError(null);
   244→
   245→    // Re-validate before opening
   246→    const isValid = await validateHarnessProject(project.path);
   247→
   248→    if (!isValid) {
   249→      setError(`Project "${project.name}" no longer contains a valid .harness directory.`);
   250→      return;
   251→    }
   252→
   253→    addToRecentProjects(project.path, project.name);
   254→    onSelectProject(project.path, project.name);
   255→    onClose();
   256→  }, [onSelectProject, onClose]);
   257→
   258→  // Handle remove recent project
   259→  const handleRemoveRecent = useCallback((e: React.MouseEvent, path: string) => {
   260→    e.stopPropagation();
   261→    const updated = removeFromRecentProjects(path);
   262→    setRecentProjects(updated);
   263→  }, []);
   264→
   265→  // Format relative time
   266→  const formatRelativeTime = (timestamp: number): string => {
   267→    const diff = Date.now() - timestamp;
   268→    const minutes = Math.floor(diff / 60000);
   269→    const hours = Math.floor(diff / 3600000);
   270→    const days = Math.floor(diff / 86400000);
   271→
   272→    if (minutes < 1) return 'Just now';
   273→    if (minutes < 60) return `${minutes}m ago`;
   274→    if (hours < 24) return `${hours}h ago`;
   275→    if (days < 7) return `${days}d ago`;
   276→    return new Date(timestamp).toLocaleDateString();
   277→  };
   278→
   279→  return (
   280→    <Modal
   281→      isOpen={isOpen}
   282→      onClose={onClose}
   283→      variant={ModalVariant.medium}
   284→      aria-label="Project Selector"
