import { useState, useCallback, useEffect } from 'react';
import {
  Modal,
  ModalVariant,
  ModalHeader,
  ModalBody,
  Form,
  FormGroup,
  FormSelect,
  FormSelectOption,
  TextInput,
  Switch,
  Card,
  CardBody,
  CardTitle,
  Flex,
  FlexItem,
  Button,
  Content,
  Divider,
} from '@patternfly/react-core';
import { motion } from 'motion/react';

export interface HQSettings {
  theme: 'light' | 'dark' | 'system';
  logBufferSize: number;
  defaultShell: string;
  ptyRows: number;
  ptyCols: number;
  autoScrollLogs: boolean;
  showTimestamps: boolean;
}

const DEFAULT_SETTINGS: HQSettings = {
  theme: 'system',
  logBufferSize: 10000,
  defaultShell: '/bin/zsh',
  ptyRows: 24,
  ptyCols: 80,
  autoScrollLogs: true,
  showTimestamps: true,
};

const STORAGE_KEY = 'hq-settings';

// Load settings from localStorage
function loadSettings(): HQSettings {
  try {
    const stored = localStorage.getItem(STORAGE_KEY);
    if (stored) {
      return { ...DEFAULT_SETTINGS, ...JSON.parse(stored) };
    }
  } catch (e) {
    console.error('Failed to load settings:', e);
  }
  return DEFAULT_SETTINGS;
}

// Save settings to localStorage
function saveSettings(settings: HQSettings): void {
  try {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(settings));
  } catch (e) {
    console.error('Failed to save settings:', e);
  }
}

interface SettingsProps {
  isOpen: boolean;
  onClose: () => void;
  onSettingsChange?: (settings: HQSettings) => void;
}

export function Settings({
  isOpen,
  onClose,
  onSettingsChange,
}: SettingsProps): React.JSX.Element {
  const [settings, setSettings] = useState<HQSettings>(loadSettings);
  const [isDirty, setIsDirty] = useState(false);

  // Load settings on mount
  useEffect(() => {
    setSettings(loadSettings());
  }, [isOpen]);

  const updateSetting = useCallback(
    <K extends keyof HQSettings>(key: K, value: HQSettings[K]) => {
      setSettings((prev) => {
        const updated = { ...prev, [key]: value };
        return updated;
      });
      setIsDirty(true);
    },
    []
  );

  const handleSave = useCallback(() => {
    saveSettings(settings);
    setIsDirty(false);
    onSettingsChange?.(settings);
    onClose();
  }, [settings, onSettingsChange, onClose]);

  const handleReset = useCallback(() => {
    setSettings(DEFAULT_SETTINGS);
    setIsDirty(true);
  }, []);

  return (
    <Modal
      isOpen={isOpen}
      onClose={onClose}
      variant={ModalVariant.medium}
      aria-label="Settings"
    >
      <ModalHeader title="Settings" />
      <ModalBody>
        <motion.div
          initial={{ opacity: 0, y: 10 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.2 }}
        >
          <Form>
            {/* Appearance Section */}
            <Card isCompact>
              <CardTitle>Appearance</CardTitle>
              <CardBody>
                <FormGroup label="Theme" fieldId="theme">
                  <FormSelect
                    id="theme"
                    value={settings.theme}
                    onChange={(_e, value) =>
                      updateSetting('theme', value as HQSettings['theme'])
                    }
                    aria-label="Theme selection"
                  >
                    <FormSelectOption value="system" label="System (Auto)" />
                    <FormSelectOption value="light" label="Light" />
                    <FormSelectOption value="dark" label="Dark" />
                  </FormSelect>
                </FormGroup>
              </CardBody>
            </Card>

            <Divider style={{ margin: '16px 0' }} />

            {/* Logs Section */}
            <Card isCompact>
              <CardTitle>Logs</CardTitle>
              <CardBody>
                <FormGroup label="Log buffer size (max entries)" fieldId="logBufferSize">
                  <TextInput
                    id="logBufferSize"
                    type="number"
                    min={100}
                    max={100000}
                    value={settings.logBufferSize}
                    onChange={(_e, value) =>
                      updateSetting('logBufferSize', Math.max(100, Math.min(100000, parseInt(value) || 10000)))
                    }
                    aria-label="Log buffer size"
                  />
                  <Content component="small" style={{ color: 'var(--pf-t--global--color--nonstatus--gray--default)' }}>
                    Number of log entries to keep in memory (100-100,000)
                  </Content>
                </FormGroup>

                <FormGroup label="" fieldId="autoScrollLogs">
                  <Switch
                    id="autoScrollLogs"
                    label="Auto-scroll logs"
                    isChecked={settings.autoScrollLogs}
                    onChange={(_e, checked) => updateSetting('autoScrollLogs', checked)}
                  />
                </FormGroup>

                <FormGroup label="" fieldId="showTimestamps">
                  <Switch
                    id="showTimestamps"
                    label="Show timestamps"
                    isChecked={settings.showTimestamps}
                    onChange={(_e, checked) => updateSetting('showTimestamps', checked)}
                  />
                </FormGroup>
              </CardBody>
            </Card>

            <Divider style={{ margin: '16px 0' }} />

            {/* Terminal Section */}
            <Card isCompact>
              <CardTitle>Terminal (PTY)</CardTitle>
              <CardBody>
                <FormGroup label="Default shell" fieldId="defaultShell">
                  <FormSelect
                    id="defaultShell"
                    value={settings.defaultShell}
                    onChange={(_e, value) => updateSetting('defaultShell', value)}
                    aria-label="Default shell"
                  >
                    <FormSelectOption value="/bin/zsh" label="Zsh (/bin/zsh)" />
                    <FormSelectOption value="/bin/bash" label="Bash (/bin/bash)" />
                    <FormSelectOption value="/bin/sh" label="Shell (/bin/sh)" />
                    <FormSelectOption value="/usr/local/bin/fish" label="Fish (/usr/local/bin/fish)" />
                  </FormSelect>
                </FormGroup>

                <Flex gap={{ default: 'gapMd' }}>
                  <FlexItem>
                    <FormGroup label="Rows" fieldId="ptyRows">
                      <TextInput
                        id="ptyRows"
                        type="number"
                        min={10}
                        max={100}
                        style={{ width: 80 }}
                        value={settings.ptyRows}
                        onChange={(_e, value) =>
                          updateSetting('ptyRows', Math.max(10, Math.min(100, parseInt(value) || 24)))
                        }
                        aria-label="Terminal rows"
                      />
                    </FormGroup>
                  </FlexItem>
                  <FlexItem>
                    <FormGroup label="Columns" fieldId="ptyCols">
                      <TextInput
                        id="ptyCols"
                        type="number"
                        min={40}
                        max={300}
                        style={{ width: 80 }}
                        value={settings.ptyCols}
                        onChange={(_e, value) =>
                          updateSetting('ptyCols', Math.max(40, Math.min(300, parseInt(value) || 80)))
                        }
                        aria-label="Terminal columns"
                      />
                    </FormGroup>
                  </FlexItem>
                </Flex>
                <Content component="small" style={{ color: 'var(--pf-t--global--color--nonstatus--gray--default)' }}>
                  Default terminal dimensions (rows x columns)
                </Content>
              </CardBody>
            </Card>

            <Divider style={{ margin: '16px 0' }} />

            {/* Actions */}
            <Flex justifyContent={{ default: 'justifyContentSpaceBetween' }}>
              <FlexItem>
                <Button variant="link" onClick={handleReset}>
                  Reset to Defaults
                </Button>
              </FlexItem>
              <FlexItem>
                <Flex gap={{ default: 'gapSm' }}>
                  <FlexItem>
                    <Button variant="tertiary" onClick={onClose}>
                      Cancel
                    </Button>
                  </FlexItem>
                  <FlexItem>
                    <Button variant="primary" onClick={handleSave} isDisabled={!isDirty}>
                      Save
                    </Button>
                  </FlexItem>
                </Flex>
              </FlexItem>
            </Flex>
          </Form>
        </motion.div>
      </ModalBody>
    </Modal>
  );
}

// Export hook for easy settings access
export function useSettings(): HQSettings {
  const [settings, setSettings] = useState<HQSettings>(loadSettings);

  useEffect(() => {
    const handleStorage = () => {
      setSettings(loadSettings());
    };
    window.addEventListener('storage', handleStorage);
    return () => window.removeEventListener('storage', handleStorage);
  }, []);

  return settings;
}

export default Settings;

